solutions.javascript:
var processQueries = function(queries, m) {
    const P = Array.from({length: m}, (_, i) => i + 1);
    const result = [];
    for (const q of queries) {
        const idx = P.indexOf(q);
        result.push(idx);
        P.splice(idx, 1);
        P.unshift(q);
    }
    return result;
};
